use std::ffi::{CStr, CString};
use std::os::raw::{c_char, c_int, c_long, c_void};
use std::os::unix::fs::MetadataExt;
use std::process;

type acl_t = *mut c_void;
type uid_t = u32;
type gid_t = u32;
type mode_t = u32;

