    ACL_TYPE_ACCESS = 0,
    ACL_TYPE_DEFAULT = 1,
    ACL_TYPE_NFS4 = 2,
}

const ACL_TEXT_APPEND_ID: c_int = 0x01;
const ACL_TEXT_NUMERIC_IDS: c_int = 0x02;
const ACL_TEXT_VERBOSE: c_int = 0x04;
const _PC_ACL_NFS4: c_int = 10;

#[repr(C)]
struct passwd {
    pw_name: *mut c_char,
    pw_passwd: *mut c_char,
    pw_uid: uid_t,
    pw_gid: gid_t,
    // ... other fields not needed
}

#[repr(C)]
