    fn acl_get_link_np(path: *const c_char, type_: acl_type_t) -> acl_t;
    fn acl_to_text_np(acl: acl_t, acllen: c_int, flags: c_int) -> *mut c_char;
    fn acl_from_mode_np(mode: mode_t) -> acl_t;
    fn acl_is_trivial_np(acl: acl_t, trivial: *mut c_int) -> c_int;
    fn acl_free(data: *mut c_void);
    fn pathconf(path: *const c_char, name: c_int) -> c_long;
    fn lpathconf(path: *const c_char, name: c_int) -> c_long;
    fn getpwuid(uid: uid_t) -> *mut passwd;
    fn getgrgid(gid: gid_t) -> *mut group;
}

