fn getuname(uid: uid_t) -> String {
    unsafe {
        let pw = getpwuid(uid);
        if pw.is_null() {
            return format!("{}", uid);
        }
        let name = (*pw).pw_name;
        let cstr = CStr::from_ptr(name);
        cstr.to_string_lossy().into_owned()
